#!/usr/bin/env python3"""Reverberant Field Analysis and DI EstimationProcesses IRs exported from Smaart (WAV format) to compute:  - Schroeder decay per octave band per position  - Spatially averaged reverberant field spectrum  - Gated direct field spectrum at reference position  - DI estimate from direct/reverberant difference  - Output plots and CSV reportUsage:    python di_analysis.py --config room_config.yaml --session session_dir/"""import osimport argparseimport yamlimport numpy as npimport scipy.signal as sigimport scipy.io.wavfile as wavfileimport matplotlib.pyplot as pltimport matplotlib.gridspec as gridspecimport pandas as pdfrom pathlib import Path# ---------------------------------------------------------------------------# Octave band definitions# ---------------------------------------------------------------------------OCTAVE_CENTRES = np.array([63, 125, 250, 500, 1000, 2000, 4000, 8000, 16000])def octave_band_limits(centre_hz):    """Return (f_low, f_high) for a 1-octave band centred at centre_hz."""    return centre_hz / np.sqrt(2), centre_hz * np.sqrt(2)# ---------------------------------------------------------------------------# IR loading# ---------------------------------------------------------------------------def load_ir(filepath):    """    Load a WAV file exported from Smaart.    Returns (ir_array, sample_rate).    Converts integer WAV formats to float64 normalised to +/-1.    """    fs, data = wavfile.read(filepath)    if data.dtype == np.int16:        data = data.astype(np.float64) / 32768.0    elif data.dtype == np.int32:        data = data.astype(np.float64) / 2147483648.0    elif data.dtype == np.float32:        data = data.astype(np.float64)    # Take first channel if stereo    if data.ndim > 1:        data = data[:, 0]    return data, int(fs)def apply_calibration(ir, fs, cal_file):    """    Apply a microphone calibration curve to an IR.    cal_file: path to a two-column CSV (frequency_hz, sensitivity_db).    Interpolates to IR frequency resolution and applies as a    frequency-domain correction.    """    if cal_file is None or not os.path.exists(cal_file):        return ir    cal = np.loadtxt(cal_file, delimiter=',', skiprows=1)    freqs = cal[:, 0]    sens_db = cal[:, 1]    n = len(ir)    fft_freqs = np.fft.rfftfreq(n, d=1.0 / fs)    # Interpolate calibration to FFT frequency bins    interp_sens = np.interp(fft_freqs, freqs, sens_db,                            left=sens_db[0], right=sens_db[-1])    correction = 10.0 ** (-interp_sens / 20.0)    spectrum = np.fft.rfft(ir)    spectrum_corrected = spectrum * correction    return np.fft.irfft(spectrum_corrected, n=n)# ---------------------------------------------------------------------------# Schroeder integration# ---------------------------------------------------------------------------def bandpass_ir(ir, fs, f_low, f_high):    """    Bandpass filter an IR using a 4th-order Butterworth filter.    Clamps band limits to valid range for the sample rate.    """    nyq = fs / 2.0    f_low = max(f_low, 10.0)    f_high = min(f_high, nyq * 0.99)    if f_low >= f_high:        return np.zeros_like(ir)    sos = sig.butter(4, [f_low / nyq, f_high / nyq],                     btype='band', output='sos')    return sig.sosfilt(sos, ir)def schroeder_decay(ir_band):    """    Compute the Schroeder backward integral of a bandpass-filtered IR.    Returns the decay curve normalised so that the initial value is 0 dB.    """    power = ir_band ** 2    # Backward cumulative sum    decay = np.cumsum(power[::-1])[::-1]    decay = np.maximum(decay, 1e-30)   # guard against log(0)    decay_db = 10.0 * np.log10(decay / decay[0])    return decay_dbdef initial_decay_level(ir, fs, centre_hz):    """    Return the initial Schroeder decay level (dB, relative) for one    octave band.  This is the reverberant energy proxy for that band.    Uses the mean level over the first 5 ms of the decay curve to    reduce sensitivity to the direct arrival peak.    """    f_low, f_high = octave_band_limits(centre_hz)    ir_band = bandpass_ir(ir, fs, f_low, f_high)    decay_db = schroeder_decay(ir_band)    # Average over first 5 ms to smooth the initial level estimate    n_avg = max(1, int(0.005 * fs))    return float(np.mean(decay_db[:n_avg]))def reverberant_spectrum(ir, fs, bands=OCTAVE_CENTRES):    """    Return the Schroeder initial decay level for each octave band.    Result is a dict {centre_hz: level_db}.    """    return {int(b): initial_decay_level(ir, fs, b) for b in bands}# ---------------------------------------------------------------------------# RT60 estimation (Sabine inversion for room constant)# ---------------------------------------------------------------------------def rt60_from_schroeder(ir, fs, centre_hz, eval_range_db=(-5, -25)):    """    Estimate RT60 in one octave band from the Schroeder decay curve.    Fits a line between eval_range_db[0] and eval_range_db[1] and    extrapolates to -60 dB.    Returns RT60 in seconds, or None if the decay is too noisy.    """    f_low, f_high = octave_band_limits(centre_hz)    ir_band = bandpass_ir(ir, fs, f_low, f_high)    decay_db = schroeder_decay(ir_band)    times = np.arange(len(decay_db)) / fs    lo, hi = eval_range_db    mask = (decay_db <= lo) & (decay_db >= hi)    if mask.sum() < 10:        return None    coeffs = np.polyfit(times[mask], decay_db[mask], 1)    # slope is dB/s; RT60 = -60 / slope    slope = coeffs[0]    if slope >= 0:        return None    return float(-60.0 / slope)def room_constant(rt60_s, volume_m3, surface_area_m2):    """    Derive the room constant R from RT60 via Sabine inversion.    R = S * alpha / (1 - alpha)    where alpha = 0.161 * V / (RT60 * S)   [Sabine]    Returns R in m^2, or None if inputs are invalid.    """    if rt60_s is None or rt60_s <= 0:        return None    alpha = 0.161 * volume_m3 / (rt60_s * surface_area_m2)    alpha = min(alpha, 0.999)    return surface_area_m2 * alpha / (1.0 - alpha)# ---------------------------------------------------------------------------# Gated direct field# ---------------------------------------------------------------------------def detect_direct_arrival(ir, fs, threshold_db=-20):    """    Find the sample index of the direct arrival.    Uses the first sample that exceeds threshold_db relative to peak.    """    power_db = 20.0 * np.log10(np.abs(ir) / (np.max(np.abs(ir)) + 1e-30))    candidates = np.where(power_db >= threshold_db)[0]    return int(candidates[0]) if len(candidates) > 0 else 0def detect_first_reflection(ir, fs, direct_idx, min_gap_ms=2.0):    """    Estimate the arrival time of the first significant reflection.    Looks for the next local peak after a minimum gap from the direct    arrival that exceeds -20 dB relative to the direct peak.    Returns sample index, or None if not found within the IR length.    """    min_gap = int(min_gap_ms * fs / 1000.0)    search_start = direct_idx + min_gap    direct_level = np.abs(ir[direct_idx])    threshold = direct_level * 10.0 ** (-20.0 / 20.0)    # Find local maxima in the search region    search = np.abs(ir[search_start:])    peaks, _ = sig.find_peaks(search, height=threshold, distance=min_gap)    if len(peaks) == 0:        return None    return int(search_start + peaks[0])def gated_direct_field(ir, fs, gate_ms=None, bands=OCTAVE_CENTRES):    """    Extract the gated direct field magnitude response.    If gate_ms is None, the gate is set automatically to 90% of the    interval between the direct arrival and the first reflection.    Returns:        freqs       : frequency array (Hz)        magnitude   : magnitude response (dB, relative to peak)        gate_ms_used: gate length actually applied (ms)    """    direct_idx = detect_direct_arrival(ir, fs)    reflection_idx = detect_first_reflection(ir, fs, direct_idx)    if gate_ms is None:        if reflection_idx is not None:            gap_samples = reflection_idx - direct_idx            gate_samples = int(0.9 * gap_samples)        else:            # Fall back to 20 ms if no reflection found            gate_samples = int(0.020 * fs)    else:        gate_samples = int(gate_ms * fs / 1000.0)    gate_ms_used = gate_samples / fs * 1000.0    # Trim IR to gate window starting at direct arrival    ir_gated = ir[direct_idx: direct_idx + gate_samples].copy()    # Apply half-Hann window    window = np.hanning(2 * len(ir_gated))[:len(ir_gated)]    ir_gated *= window    # Zero-pad to next power of 2 for FFT efficiency    n_fft = int(2 ** np.ceil(np.log2(len(ir_gated))))    spectrum = np.fft.rfft(ir_gated, n=n_fft)    freqs = np.fft.rfftfreq(n_fft, d=1.0 / fs)    magnitude = 20.0 * np.log10(np.abs(spectrum) + 1e-30)    magnitude -= np.max(magnitude)   # normalise to 0 dB peak    return freqs, magnitude, gate_ms_useddef direct_field_at_bands(ir, fs, gate_ms=None, bands=OCTAVE_CENTRES):    """    Return the mean direct field level in each octave band (dB, relative).    """    freqs, magnitude, gate_ms_used = gated_direct_field(ir, fs, gate_ms)    levels = {}    for b in bands:        f_low, f_high = octave_band_limits(b)        mask = (freqs >= f_low) & (freqs < f_high)        if mask.sum() > 0:            # Average in power domain            power = 10.0 ** (magnitude[mask] / 10.0)            levels[int(b)] = float(10.0 * np.log10(np.mean(power)))        else:            levels[int(b)] = np.nan    return levels, gate_ms_used# ---------------------------------------------------------------------------# Spatial averaging of reverberant field# ---------------------------------------------------------------------------def spatial_average_reverberant(ir_list, fs, bands=OCTAVE_CENTRES):    """    Compute the spatially averaged reverberant field spectrum.    ir_list: list of IR arrays (one per microphone position).    Averaging is performed in the power domain.    Returns dict {centre_hz: averaged_level_db}.    """    all_spectra = [reverberant_spectrum(ir, fs, bands) for ir in ir_list]    averaged = {}    for b in bands:        b = int(b)        levels_db = [s[b] for s in all_spectra]        # Convert to linear power, average, convert back        powers = [10.0 ** (l / 10.0) for l in levels_db]        averaged[b] = float(10.0 * np.log10(np.mean(powers)))    return averaged# ---------------------------------------------------------------------------# DI estimation# ---------------------------------------------------------------------------def estimate_di(direct_levels, reverberant_levels,                rt60_per_band, volume_m3, surface_area_m2,                bands=OCTAVE_CENTRES):    """    Estimate DI(f) per octave band.    DI(f) = Direct(f) - Reverberant(f) + 10*log10(4 / R(f))    where R(f) is the room constant derived from RT60 and room geometry.    Returns dict {centre_hz: DI_dB}.    """    di = {}    for b in bands:        b = int(b)        d = direct_levels.get(b, np.nan)        r = reverberant_levels.get(b, np.nan)        rt60 = rt60_per_band.get(b)        R = room_constant(rt60, volume_m3, surface_area_m2)        if np.isnan(d) or np.isnan(r) or R is None or R <= 0:            di[b] = np.nan            continue        room_correction = 10.0 * np.log10(4.0 / R)        di[b] = float(d - r + room_correction)    return didef rt60_per_band_from_irs(ir_list, fs, bands=OCTAVE_CENTRES):    """    Estimate RT60 per octave band by averaging across all IR positions.    Returns dict {centre_hz: RT60_seconds}.    """    rt60_all = {int(b): [] for b in bands}    for ir in ir_list:        for b in bands:            rt = rt60_from_schroeder(ir, fs, b)            if rt is not None:                rt60_all[int(b)].append(rt)    return {b: float(np.mean(v)) if v else None            for b, v in rt60_all.items()}# ---------------------------------------------------------------------------# Plotting# ---------------------------------------------------------------------------def plot_results(direct_levels, reverberant_levels, di_estimates,                 rt60_per_band, gate_ms_used, channel_name,                 output_dir, bands=OCTAVE_CENTRES):    """    Generate a four-panel output figure per speaker channel.    """    bands_int = [int(b) for b in bands]    band_labels = [str(b) for b in bands_int]    direct_vals = [direct_levels.get(b, np.nan) for b in bands_int]    reverb_vals = [reverberant_levels.get(b, np.nan) for b in bands_int]    di_vals = [di_estimates.get(b, np.nan) for b in bands_int]    rt60_vals = [rt60_per_band.get(b) for b in bands_int]    rt60_vals = [v if v is not None else np.nan for v in rt60_vals]    # Normalise direct and reverberant to 0 dB at 1 kHz for comparison    ref_band = 1000    d_ref = direct_levels.get(ref_band, 0.0) or 0.0    r_ref = reverberant_levels.get(ref_band, 0.0) or 0.0    direct_norm = [v - d_ref for v in direct_vals]    reverb_norm = [v - r_ref for v in reverb_vals]    fig = plt.figure(figsize=(14, 10))    fig.suptitle(f"Reverberant Field Analysis Ń {channel_name}", fontsize=13)    gs = gridspec.GridSpec(2, 2, figure=fig, hspace=0.4, wspace=0.35)    x = np.arange(len(bands_int))    # Panel 1: Direct vs reverberant field    ax1 = fig.add_subplot(gs[0, 0])    ax1.plot(x, direct_norm, 'o-', color='steelblue',             label=f'Direct field (gated {gate_ms_used:.1f} ms)')    ax1.plot(x, reverb_norm, 's--', color='firebrick',             label='Reverberant field (spatially averaged)')    ax1.axhline(0, color='grey', linewidth=0.5, linestyle=':')    ax1.set_xticks(x)    ax1.set_xticklabels(band_labels, rotation=45)    ax1.set_xlabel('Octave band centre (Hz)')    ax1.set_ylabel('Level (dB, normalised at 1 kHz)')    ax1.set_title('Direct vs Reverberant Field')    ax1.legend(fontsize=8)    ax1.grid(True, alpha=0.3)    # Panel 2: DI estimate    ax2 = fig.add_subplot(gs[0, 1])    valid = [(i, v) for i, v in enumerate(di_vals) if not np.isnan(v)]    if valid:        xi, yi = zip(*valid)        ax2.plot(list(xi), list(yi), 'D-', color='darkorange')    ax2.set_xticks(x)    ax2.set_xticklabels(band_labels, rotation=45)    ax2.set_xlabel('Octave band centre (Hz)')    ax2.set_ylabel('DI (dB)')    ax2.set_title('Estimated Directivity Index DI(f)')    ax2.grid(True, alpha=0.3)    # Panel 3: RT60 per band    ax3 = fig.add_subplot(gs[1, 0])    ax3.bar(x, rt60_vals, color='mediumseagreen', alpha=0.7)    ax3.set_xticks(x)    ax3.set_xticklabels(band_labels, rotation=45)    ax3.set_xlabel('Octave band centre (Hz)')    ax3.set_ylabel('RT60 (s)')    ax3.set_title('RT60 per Octave Band')    ax3.grid(True, alpha=0.3, axis='y')    # Panel 4: Direct minus reverberant (raw difference, no room correction)    diff = [d - r for d, r in zip(direct_norm, reverb_norm)]    ax4 = fig.add_subplot(gs[1, 1])    ax4.plot(x, diff, '^-', color='mediumpurple')    ax4.axhline(0, color='grey', linewidth=0.5, linestyle=':')    ax4.set_xticks(x)    ax4.set_xticklabels(band_labels, rotation=45)    ax4.set_xlabel('Octave band centre (Hz)')    ax4.set_ylabel('Difference (dB)')    ax4.set_title('Direct minus Reverberant (uncorrected)')    ax4.grid(True, alpha=0.3)    out_path = Path(output_dir) / f"{channel_name}_analysis.png"    fig.savefig(out_path, dpi=150, bbox_inches='tight')    plt.close(fig)    print(f"  Plot saved: {out_path}")# ---------------------------------------------------------------------------# CSV report# ---------------------------------------------------------------------------def save_csv(direct_levels, reverberant_levels, di_estimates,             rt60_per_band, channel_name, output_dir,             bands=OCTAVE_CENTRES):    bands_int = [int(b) for b in bands]    rows = []    for b in bands_int:        rows.append({            'channel': channel_name,            'band_hz': b,            'direct_field_db': round(direct_levels.get(b, np.nan), 2),            'reverberant_field_db': round(reverberant_levels.get(b, np.nan), 2),            'di_estimate_db': round(di_estimates.get(b, np.nan), 2),            'rt60_s': round(rt60_per_band.get(b) or np.nan, 3),        })    df = pd.DataFrame(rows)    out_path = Path(output_dir) / f"{channel_name}_results.csv"    df.to_csv(out_path, index=False)    print(f"  CSV saved: {out_path}")    return df# ---------------------------------------------------------------------------# Main session processor# ---------------------------------------------------------------------------def process_channel(channel_cfg, room_cfg, session_dir, output_dir):    """    Process one speaker channel.    channel_cfg: dict from config file describing this channel.    room_cfg: dict with room geometry and mic calibration info.    """    channel_name = channel_cfg['name']    print(f"\nProcessing channel: {channel_name}")    volume = room_cfg['volume_m3']    surface = room_cfg['surface_area_m2']    # Load IRs for all positions    ir_files = sorted(Path(session_dir).glob(        f"{channel_cfg['ir_prefix']}*.wav"))    if not ir_files:        print(f"  WARNING: no IR files found for {channel_name}, skipping.")        return None    irs = []    ref_ir = None    cal_map = {c['channel']: c.get('cal_file')               for c in room_cfg.get('microphone_calibration', [])}    for i, f in enumerate(ir_files):        ir, fs = load_ir(f)        cal_file = cal_map.get(i + 1)        ir = apply_calibration(ir, fs, cal_file)        irs.append(ir)        if i == 0:            ref_ir = ir   # first file is reference position by convention            ref_fs = fs    print(f"  Loaded {len(irs)} IR files at {ref_fs} Hz")    # Gated direct field at reference position    gate_ms = channel_cfg.get('gate_ms', None)    direct_levels, gate_ms_used = direct_field_at_bands(ref_ir, ref_fs,                                                         gate_ms=gate_ms)    print(f"  Gate applied: {gate_ms_used:.1f} ms")    # RT60 per band from all positions    rt60_bands = rt60_per_band_from_irs(irs, ref_fs)    for b, rt in rt60_bands.items():        if rt:            print(f"  RT60 {b:5d} Hz: {rt:.3f} s")    # Spatially averaged reverberant field    reverb_levels = spatial_average_reverberant(irs, ref_fs)    # DI estimate    di = estimate_di(direct_levels, reverb_levels,                     rt60_bands, volume, surface)    print("  DI estimates (dB):")    for b, v in di.items():        print(f"    {b:5d} Hz: {v:.1f}" if not np.isnan(v)              else f"    {b:5d} Hz: n/a")    # Outputs    plot_results(direct_levels, reverb_levels, di, rt60_bands,                 gate_ms_used, channel_name, output_dir)    df = save_csv(direct_levels, reverb_levels, di, rt60_bands,                  channel_name, output_dir)    return dfdef run_session(config_path, session_dir, output_dir):    with open(config_path, 'r') as f:        config = yaml.safe_load(f)    room_cfg = config['room']    Path(output_dir).mkdir(parents=True, exist_ok=True)    all_results = []    for ch in config['channels']:        df = process_channel(ch, room_cfg, session_dir, output_dir)        if df is not None:            all_results.append(df)    if all_results:        summary = pd.concat(all_results, ignore_index=True)        summary_path = Path(output_dir) / 'session_summary.csv'        summary.to_csv(summary_path, index=False)        print(f"\nSession summary saved: {summary_path}")# ---------------------------------------------------------------------------# Entry point# ---------------------------------------------------------------------------if __name__ == '__main__':    parser = argparse.ArgumentParser(        description='Reverberant field analysis and DI estimation')    parser.add_argument('--config', required=True,                        help='Path to room_config.yaml')    parser.add_argument('--session', required=True,                        help='Directory containing exported IR WAV files')    parser.add_argument('--output', default='output',                        help='Directory for plots and CSV reports')    args = parser.parse_args()    run_session(args.config, args.session, args.output)